from typing import List
from functools import lru_cache

class Solution:
    def specialPerm(self, nums: List[int]) -> int:
        MOD = 10**9 + 7
        n = len(nums)

        @lru_cache(maxsize=None)
        def dp(pos, mask):
            if mask == (1 << n) - 1:
                return 1
            total = 0
            for i in range(n):
                if not (mask & (1 << i)):
                    if pos == -1 or (nums[i] % nums[pos] == 0 or nums[pos] % nums[i] == 0):
                        total += dp(i, mask | (1 << i))
                        total %= MOD
            return total

        return dp(-1, 0)
